tool_calls:
set -euo pipefail
mkdir -p /reports
awk '
  $1=="PASS" {passed++; total++; next}
  $1=="FAIL" {failed++; total++; failures[++nf]=$2; next}
  NF {total++}
  END {
    print "# Test Summary"
    print ""
    printf "Total: %d | Passed: %d | Failed: %d\n", total, passed, failed
    print ""
    print "## Failures"
    for (i=1; i<=nf; i++) print "- " failures[i]
  }
' /data/test-results.txt | tee /reports/test-summary.md

